const out = $input.first().json.stdout || '';
const skipped = out.startsWith('SKIP:');
const success = out.includes('SUCCESS');
const committed = out.match(/\[master [a-f0-9]+\]/);
return [{ json: { skipped, success, committed: committed ? committed[0] : null, output: out.slice(-2000) } }];
